module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    integer i;

    always @(A, B) begin
        dividend = A;
        divisor = B;
        remainder = 0;
        result = 0;

        for (i = 15; i >= 0; i = i - 1) begin
            remainder = {remainder[14:0], dividend[i]};
            if (remainder >= divisor) begin
                remainder = remainder - divisor;
                result[i] = 1;
            end else begin
                result[i] = 0;
            end
        end

        odd = remainder;
    end

endmodule
